// src/pages/HomeScreen.js
import React from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TouchableOpacity,
  ScrollView,
} from "react-native";
import { useNavigation } from "@react-navigation/native";

// ✅ From src/pages -> root/assets = ../../assets
// taxi.png already INCLUDES the big green check pin
const taxiImg = require("../../assets/taxi.png");

// urban.png already INCLUDES the “Communauté Urbaine de Yaoundé” text
const cityLogo = require("../../assets/urban.png");

const tickCircle = require("../../assets/tickcircle.png");
const shieldLock = require("../../assets/shieldd.png");

export default function HomeScreen() {
  const navigation = useNavigation();
  const plateNumber = "CE696KO";

  const goToOfficialControl = () => {
    // Keep disabled for now since you only have HomeScreen
    // navigation.navigate("official-control");
  };

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}>
        <View style={styles.screen}>
          {/* ===== HERO IMAGE (already contains taxi + big green pin) ===== */}
          <View style={styles.heroWrap}>
            <View style={styles.faintCircle} />

            <View style={styles.heroCard}>
              <Image source={taxiImg} style={styles.taxi} resizeMode="contain" />
            </View>
          </View>

          {/* ===== STATUS ===== */}
          <View style={styles.statusRow}>
            <Image source={tickCircle} style={styles.smallTick} resizeMode="contain" />
            <Text style={styles.statusText}>Vérifié</Text>
          </View>

          {/* ===== PLATE ===== */}
          <View style={styles.plateWrap}>
            <Text style={styles.plateText}>{plateNumber}</Text>
          </View>

          {/* ===== BUTTON ===== */}
          <TouchableOpacity activeOpacity={0.92} style={styles.officialBtn} onPress={goToOfficialControl}>
            <Image source={shieldLock} style={styles.btnIcon} resizeMode="contain" />
            <Text style={styles.btnText}>Contrôle officiel</Text>
          </TouchableOpacity>

          {/* ===== LOGO (already includes text in the image) ===== */}
          <View style={styles.logoWrap}>
            <Image source={cityLogo} style={styles.logo} resizeMode="contain" />
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#F2F5FA" },
  scroll: { paddingBottom: 34 },
  screen: { paddingTop: 18, paddingHorizontal: 18, alignItems: "center" },

  /* ===== HERO ===== */
  heroWrap: {
    width: "100%",
    height: 320,
    alignItems: "center",
    justifyContent: "center",
    position: "relative",
    marginTop: 6,
  },
  faintCircle: {
    position: "absolute",
    width: 320,
    height: 320,
    borderRadius: 160,
    backgroundColor: "#E9EEF6",
    opacity: 0.65,
  },

  // ✅ soft white card behind taxi image (like mockup)
  heroCard: {
    width: "92%",
    height: 205,
    borderRadius: 22,
    backgroundColor: "rgba(255,255,255,0.72)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.06)",
    alignItems: "center",
    justifyContent: "center",
    shadowColor: "#000",
    shadowOpacity: 0.10,
    shadowRadius: 18,
    shadowOffset: { width: 0, height: 10 },
    elevation: 6,
  },

  taxi: {
    width: "96%",
    height: 185,
  },

  /* ===== STATUS ===== */
  statusRow: {
    flexDirection: "row",
    alignItems: "center",
    marginTop: 14,
    gap: 12,
  },
  smallTick: { width: 40, height: 40 },
  statusText: {
    fontSize: 44,
    fontWeight: "900",
    color: GREEN,
    letterSpacing: 0.3,
  },

  /* ===== PLATE ===== */
  plateWrap: {
    marginTop: 18,
    width: "92%",
    borderRadius: 22,
    borderWidth: 4,
    borderColor: GREEN,
    backgroundColor: "#FFFFFF",
    paddingVertical: 18,
    alignItems: "center",
    shadowColor: "#000",
    shadowOpacity: 0.10,
    shadowRadius: 16,
    shadowOffset: { width: 0, height: 10 },
    elevation: 5,
  },
  plateText: {
    fontSize: 58,
    fontWeight: "900",
    letterSpacing: 1.5,
    color: "#111827",
  },

  /* ===== BUTTON ===== */
  officialBtn: {
    marginTop: 18,
    width: "92%",
    height: 72,
    backgroundColor: DARK_GREEN,
    borderRadius: 20,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    gap: 12,
    shadowColor: "#000",
    shadowOpacity: 0.22,
    shadowRadius: 18,
    shadowOffset: { width: 0, height: 14 },
    elevation: 8,
    borderWidth: 1,
    borderColor: "rgba(255,255,255,0.16)",
  },
  btnIcon: { width: 24, height: 24, opacity: 0.95 },
  btnText: {
    color: "#FFFFFF",
    fontSize: 26,
    fontWeight: "900",
    letterSpacing: 0.2,
  },

  /* ===== LOGO ===== */
  logoWrap: { marginTop: 26, alignItems: "center" },
  logo: { width: 170, height: 170 }, // ✅ larger like mockup bottom block
});
